/*acordeón*/
.accordion {
 background-color: white;
 color: #444;
 cursor: pointer;
 padding: 18px;
 width: 100%;
 border: 0,5 px solid #007691;
 text-align: left;
 outline: none;
 font-size: 15px;
 transition: 0.4s;
}

.active2, .accordion:hover {
 background-color: #ccc;
}

.accordion:after {
 content: '\002B';
 color: #777;
 font-weight: bold;
 float: right;
 margin-left: 5px;
}

.active2:after {
 content: "\2212";
}

/*Estilos para los acordeones de cada bloque*/
.accordion1, .accordion2, .accordion3, .accordion4{
 background-color: white;
 color: #000;
 cursor: pointer;
 padding: 18px;
 width: 100%;
 border: 1.5px solid #007691;
 text-align: left;
 outline: none;
 font-size: 15px;
 transition: 0.4s;
}

.active2, .accordion1:hover, .accordion2:hover, .accordion3:hover, .accordion4:hover{
 background-color: #dcf2f7;
}
.accordion1:after, .accordion2:after, .accordion3:after, .accordion4:after, {
 content: '\002B';
 color: #007691;
 font-weight: bold;
 float: right;
 margin-left: 5px;
}
/*Añadir + para desplegar accordion pesonalizado*/
.active2, .accordion1:after, .accordion2:after, .accordion3:after, .accordion4:after {
 content: "\002B";
float: right;
}

